{
  "needs_interview": true,
  "questions": [
    {
      "question": "The acceptance criteria claim base=17, voice=10, brain=8 packages, but implementation steps describe base=7, voice=10, brain=16 packages. The actual v1 files have requirements.txt=16, requirements-voice.txt=10, requirements-brain.txt=7. Which structure is correct?",
      "options": [
        "Follow implementation steps (7, 10, 16) — AC numbers are errors",
        "Follow AC (17, 10, 8) — implementation steps are outdated",
        "Follow actual v1 files (16, 10, 7) — both AC and implementation steps need fixes"
      ]
    },
    {
      "question": "The AC states 'Git shows changed files (not new files)' but Files to Create/Modify says 'create'. Should we update the v1 requirements files in the root directory, or create new pinned files in cyrus2/?",
      "options": [
        "Update v1 files in root (main.py, cyrus_voice.py, cyrus_brain.py directory level)",
        "Create new pinned files in cyrus2/ directory (for the rewrite)",
        "Do both — pin v1 files AND create copies in cyrus2/"
      ]
    },
    {
      "question": "GPU compatibility verification (torch, onnxruntime-gpu, kokoro-onnx) requires checking CUDA version compatibility. Should the implementation research compatible versions from package docs, or is there a known-good GPU environment to test against?",
      "options": [
        "Research compatible versions from package changelog/docs/GitHub issues",
        "There is a test environment available with GPU hardware to validate",
        "Skip GPU compatibility testing — just use pip freeze from current environment"
      ]
    }
  ]
}

